const PRESET_SPRITES={
link:{name:'Link',icon:'⚔️',title:'The Chosen Hero',img:"data:image/png;base64,"},
zelda:{name:'Zelda',icon:'👑',title:'Princess of Hyrule',img:"data:image/png;base64,"},
lana:{name:'Lana',icon:'📖',title:'Guardian Sorceress',img:"data:image/png;base64,"},
impa:{name:'Impa',icon:'🗡️',title:'The Shiekah Warrior',img:"data:image/png;base64,"},
linkle:{name:'Linkle',icon:'🏹',title:'The Lost Heroine',img:"data:image/png;base64,"},
fi:{name:'Fi',icon:'💎',title:'Spirit of the Sword',img:"data:image/png;base64,"},
wolf_link:{name:'Wolf Link',icon:'🐺',title:'The Twilight Beast',img:"data:image/png;base64,"},
darunia:{name:'Darunia',icon:'🔥',title:'Goron Sage',img:"data:image/png;base64,"},
ruto:{name:'Ruto',icon:'🌊',title:'Zora Princess',img:"data:image/png;base64,"},
sheik:{name:'Sheik',icon:'🌙',title:'Shadow of Hyrule',img:"data:image/png;base64,"},
ganondorf:{name:'Ganondorf',icon:'💀',title:'Demon King',img:"data:image/png;base64,"},
ghirahim:{name:'Ghirahim',icon:'🗡️',title:'Demon Lord',img:"data:image/png;base64,"},
zant:{name:'Zant',icon:'👁️',title:'Usurper King',img:"data:image/png;base64,"}
};

function renderSprite(el,key,sz){if(!el)return;var s=PRESET_SPRITES[key]||PRESET_SPRITES.link;el.innerHTML='<img src="'+s.img+'" style="width:'+(sz||80)+'px;height:'+(sz||80)+'px;image-rendering:auto;object-fit:contain" alt="'+s.name+'" />';}
function renderSpriteToCanvas(c,key){if(!c)return;var s=PRESET_SPRITES[key]||PRESET_SPRITES.link;var i=new Image();i.onload=function(){var x=c.getContext('2d');x.clearRect(0,0,c.width,c.height);x.drawImage(i,0,0,c.width,c.height);};i.src=s.img;}